              "content": "/**
 * Portum Router — provider dispatch, body translation, response normalization.
 *
 * Fixes applied:
 *   - Anthropic body translation (system→top-level, max_tokens required)
 *   - MiniMax switched to OpenAI-compatible /v1/chat/completions
 *   - Missing API key returns a proper error object (not a fake 200)
 *   - stream:true rejected explicitly
 *   - Dead xiaomi/mimo routing removed
 *   - Cost estimation per request
 */

// ─── Shared Types ───────────────────────────────────────────────────

interface ChatMessage {
  role: "system" | "user" | "assistant" | "tool";
  content: string;
  name?: string;
}

export interface ChatCompletionRequest {
  model: string;
  messages: ChatMessage[];
  max_tokens?: number;
  temperature?: number;
  stream?: boolean;
}

interface ChatCompletionChoice {
  index: number;
  message: ChatMessage;
  finish_reason: "stop" | "length" | "tool_calls" | "content_filter" | null;
}

export interface ChatCompletionUsage {
  prompt_tokens: number;
  completion_tokens: number;
  total_tokens: number;
}

export interface ChatCompletionResponse {
  id: string;
  object: "chat.completion";
  created: number;
  model: string;
  choices: ChatCompletionChoice[];
  usage: ChatCompletionUsage;
}

export type ProviderName = "openai" | "anthropic" | "modelstudio" | "minimax" | "openrouter";

interface ProviderConfig {
  name: ProviderName;
  url: string;
  apiKeyEnv: string;
}

interface UpstreamUsage {
  prompt_tokens?: number;
  input_tokens?: number;
  completion_tokens?: number;
  output_tokens?: number;
  total_tokens?: number;
}

// ─── Route Result (carries error status for proper HTTP codes) ───────

export interface RouteResult {
  response: ChatCompletionResponse;
  /** Non-null when the request failed at the routing layer. */
  error: { status: number; message: string } | null;
  provider: ProviderName;
  responseTimeMs: number;
  estimatedCostUsd: number;
}

// ─── Provider Registry ──────────────────────────────────────────────

const PROVIDERS: Record<ProviderName, ProviderConfig> = {
  openai: {
    name: "openai",
    url: "https://api.openai.com/v1/chat/completions",
    apiKeyEnv: "OPENAI_API_KEY",
  },
  anthropic: {
    name: "anthropic",
    url: "https://api.anthropic.com/v1/messages",
    apiKeyEnv: "ANTHROPIC_API_KEY",
  },
  modelstudio: {
    name: "modelstudio",
    url: "https://dashscope-us.aliyuncs.com/compatible-mode/v1/chat/completions",
    apiKeyEnv: "DASHSCOPE_API_KEY",
  },
  minimax: {
    name: "minimax",
    // Use the OpenAI-compatible endpoint, not chatcompletion_pro
    url: "https://api.minimax.chat/v1/chat/completions",
    apiKeyEnv: "MINIMAX_API_KEY",
  },
  openrouter: {
    name: "openrouter",
    url: "https://openrouter.ai/api/v1/chat/completions",
    apiKeyEnv: "OPENROUTER_API_KEY",
  },
};

export function getAllProviders(): Record<ProviderName, { url: string; apiKeyEnv: string }> {
  const out: Record<string, { url: string; apiKeyEnv: string }> = {};
  for (const [name, cfg] of Object.entries(PROVIDERS)) {
    out[name] = { url: cfg.url, apiKeyEnv: cfg.apiKeyEnv };
  }
  return out as Record<ProviderName, { url: string; apiKeyEnv: string }>;
}

// ─── Cost Estimation ────────────────────────────────────────────────
// Rough $/1K-token rates. Good enough for dashboard estimates.

const COST_PER_1K: Record<string, { input: number; output: number }> = {
  "gpt-4o":          { input: 0.0025, output: 0.01 },
  "gpt-4o-mini":     { input: 0.00015, output: 0.0006 },
  "gpt-4.1":         { input: 0.002, output: 0.008 },
  "gpt-4.1-mini":    { input: 0.0004, output: 0.0016 },
  "gpt-4.1-nano":    { input: 0.0001, output: 0.0004 },
  "claude-sonnet-4-6":{ input: 0.003, output: 0.015 },
  "claude-opus-4-6": { input: 0.015, output: 0.075 },
  "claude-haiku-4-5":{ input: 0.0008, output: 0.004 },
  "qwen3.6-plus":    { input: 0.0005, output: 0.002 },
  "qwen3.5":         { input: 0.0002, output: 0.0006 },
};

function estimateCost(model: string, usage: ChatCompletionUsage): number {
  const key = Object.keys(COST_PER_1K).find((k) => model.toLowerCase().includes(k.toLowerCase()));
  const rates = key ? COST_PER_1K[key] : { input: 0.001, output: 0.003 };
  return Number(
    ((usage.prompt_tokens / 1000) * rates.input +
      (usage.completion_tokens / 1000) * rates.output).toFixed(6),
  );
}

// ─── Model → Provider Routing ───────────────────────────────────────

function providerForModel(model: string): ProviderConfig {
  const normalized = model.toLowerCase();

  if (normalized.startsWith("gpt-")) return PROVIDERS.openai;
  if (normalized.startsWith("o1") || normalized.startsWith("o3") || normalized.startsWith("o4")) return PROVIDERS.openai;
  if (normalized.startsWith("claude-")) return PROVIDERS.anthropic;
  if (normalized.startsWith("qwen") || normalized.startsWith("glm")) return PROVIDERS.modelstudio;
  if (normalized.startsWith("minimax")) return PROVIDERS.minimax;

  // Everything else goes to OpenRouter
  return PROVIDERS.openrouter;
}

export function getProviderForModel(model: string): ProviderName {
  return providerForModel(model).name;
}

// ─── Request Body Translation ───────────────────────────────────────

function buildHeaders(provider: ProviderConfig, apiKey: string): Record<string, string> {
  if (provider.name === "anthropic") {
    return {
      "content-type": "application/json",
      "x-api-key": apiKey,
      "anthropic-version": "2023-06-01",
    };
  }
  return {
    "content-type": "application/json",
    authorization: `Bearer ${apiKey}`,
  };
}

/**
 * Translate an OpenAI-shaped request into Anthropic Messages API format.
 *
 * Key differences:
 *   - system messages must be a top-level `system` string, not in messages[]
 *   - max_tokens is required (default to 4096)
 *   - role "tool" is not supported in the same way
 */
function translateForAnthropic(
  request: ChatCompletionRequest,
): Record<string, unknown> {
  const systemParts: string[] = [];
  const messages: Array<{ role: string; content: string }> = [];

  for (const msg of request.messages) {
    if (msg.role === "system") {
      systemParts.push(msg.content);
    } else {
      messages.push({ role: msg.role, content: msg.content });
    }
  }

  const body: Record<string, unknown> = {
    model: request.model,
    messages,
    max_tokens: request.max_tokens ?? 4096,
  };

  if (systemParts.length > 0) {
    body.system = systemParts.join("\n\n");
  }

  if (request.temperature !== undefined) {
    body.temperature = request.temperature;
  }

  return body;
}

/**
 * Build the upstream request body. Most providers accept the raw
 * OpenAI shape; Anthropic needs translation.
 */
function buildRequestBody(
  provider: ProviderConfig,
  request: ChatCompletionRequest,
): string {
  if (provider.name === "anthropic") {
    return JSON.stringify(translateForAnthropic(request));
  }

  // Strip stream:true — we already rejected it at the server level,
  // but belt-and-suspenders: never forward it.
  const { stream: _ignored, ...rest } = request;
  return JSON.stringify(rest);
}

// ─── Response Normalization ─────────────────────────────────────────

function makeResponse(model: string, content: string): ChatCompletionResponse {
  return {
    id: `chatcmpl-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
    object: "chat.completion",
    created: Math.floor(Date.now() / 1000),
    model,
    choices: [
      {
        index: 0,
        message: { role: "assistant", content },
        finish_reason: "stop",
      },
    ],
    usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 },
  };
}

function normalizeUsage(usage: UpstreamUsage | undefined): ChatCompletionUsage {
  const promptTokens = usage?.prompt_tokens ?? usage?.input_tokens ?? 0;
  const completionTokens = usage?.completion_tokens ?? usage?.output_tokens ?? 0;
  return {
    prompt_tokens: promptTokens,
    completion_tokens: completionTokens,
    total_tokens: usage?.total_tokens ?? promptTokens + completionTokens,
  };
}

function extractTextContent(content: unknown): string {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    const parts = content
      .map((item) => {
        if (typeof item === "string") return item;
        if (item && typeof item === "object" && "text" in item) {
          const text = (item as { text?: unknown }).text;
          return typeof text === "string" ? text : "";
        }
        return "";
      })
      .filter(Boolean);
    if (parts.length > 0) return parts.join("\n");
  }
  return "";
}

function normalizeResponse(
  request: ChatCompletionRequest,
  payload: unknown,
): ChatCompletionResponse {
  if (!payload || typeof payload !== "object") {
    return makeResponse(request.model, "Upstream returned an invalid response payload.");
  }

  const record = payload as {
    id?: unknown;
    model?: unknown;
    usage?: UpstreamUsage;
    choices?: Array<{
      index?: unknown;
      finish_reason?: unknown;
      message?: { role?: unknown; content?: unknown };
    }>;
    content?: unknown;
    stop_reason?: unknown;
  };

  // OpenAI-shaped response
  const choice = record.choices?.[0];
  const choiceContent = extractTextContent(choice?.message?.content);
  if (choice && choiceContent) {
    return {
      id: typeof record.id === "string" ? record.id : makeResponse(request.model, "").id,
      object: "chat.completion",
      created: Math.floor(Date.now() / 1000),
      model: typeof record.model === "string" ? record.model : request.model,
      choices: [
        {
          index: typeof choice.index === "number" ? choice.index : 0,
          message: { role: "assistant", content: choiceContent },
          finish_reason:
            typeof choice.finish_reason === "string"
              ? (choice.finish_reason as ChatCompletionChoice["finish_reason"])
              : "stop",
        },
      ],
      usage: normalizeUsage(record.usage),
    };
  }

  // Anthropic-shaped response
  const anthropicContent = extractTextContent(record.content);
  if (anthropicContent) {
    return {
      id: typeof record.id === "string" ? record.id : makeResponse(request.model, "").id,
      object: "chat.completion",
      created: Math.floor(Date.now() / 1000),
      model: typeof record.model === "string" ? record.model : request.model,
      choices: [
        {
          index: 0,
          message: { role: "assistant", content: anthropicContent },
          finish_reason:
            typeof record.stop_reason === "string"
              ? (record.stop_reason as ChatCompletionChoice["finish_reason"])
              : "stop",
        },
      ],
      usage: normalizeUsage(record.usage),
    };
  }

  return makeResponse(request.model, "Upstream response did not contain assistant content.");
}

async function safeJson(response: Response): Promise<unknown> {
  const text = await response.text();
  if (!text) return {};
  try {
    return JSON.parse(text) as unknown;
  } catch {
    return { raw: text };
  }
}

function describeErrorPayload(payload: unknown): string {
  if (!payload) return "No error details returned.";
  if (typeof payload === "string") return payload;
  if (typeof payload === "object") {
    const record = payload as {
      error?: { message?: unknown; type?: unknown };
      message?: unknown;
      raw?: unknown;
      base_resp?: { status_msg?: unknown };
    };
    if (record.error?.message && typeof record.error.message === "string") return record.error.message;
    if (record.message && typeof record.message === "string") return record.message;
    if (record.base_resp?.status_msg && typeof record.base_resp.status_msg === "string") return record.base_resp.status_msg;
    if (record.raw && typeof record.raw === "string") return record.raw;
  }
  return JSON.stringify(payload);
}

// ─── Main Dispatch ──────────────────────────────────────────────────

export async function routeRequest(
  request: ChatCompletionRequest,
): Promise<RouteResult> {
  const startMs = Date.now();
  const provider = providerForModel(request.model);

  // Reject streaming explicitly
  if (request.stream) {
    const elapsed = Date.now() - startMs;
    return {
      response: makeResponse(request.model, ""),
      error: { status: 400, message: "Portum does not support streaming. Set stream:false or omit the field." },
      provider: provider.name,
      responseTimeMs: elapsed,
      estimatedCostUsd: 0,
    };
  }

  const apiKey = process.env[provider.apiKeyEnv];
  if (!apiKey) {
    const elapsed = Date.now() - startMs;
    return {
      response: makeResponse(request.model, ""),
      error: {
        status: 502,
        message: `Provider ${provider.name} not configured: missing env var ${provider.apiKeyEnv}`,
      },
      provider: provider.name,
      responseTimeMs: elapsed,
      estimatedCostUsd: 0,
    };
  }

  try {
    const response = await fetch(provider.url, {
      method: "POST",
      headers: buildHeaders(provider, apiKey),
      body: buildRequestBody(provider, request),
    });

    const payload = await safeJson(response);

    if (!response.ok) {
      const elapsed = Date.now() - startMs;
      return {
        response: makeResponse(request.model, ""),
        error: {
          status: response.status,
          message: `Upstream ${provider.name} error (${response.status}): ${describeErrorPayload(payload)}`,
        },
        provider: provider.name,
        responseTimeMs: elapsed,
        estimatedCostUsd: 0,
      };
    }

    const normalized = normalizeResponse(request, payload);
    const elapsed = Date.now() - startMs;
    return {
      response: normalized,
      error: null,
      provider: provider.name,
      responseTimeMs: elapsed,
      estimatedCostUsd: estimateCost(request.model, normalized.usage),
    };
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    const elapsed = Date.now() - startMs;
    return {
      response: makeResponse(request.model, ""),
      error: { status: 502, message: `Routing error: ${message}` },
      provider: provider.name,
      responseTimeMs: elapsed,
      estimatedCostUsd: 0,
    };
  }
}
